/**
 * Webhook notification adapter — delivers notifications via HTTP POST to a URL.
 *
 * Implements NotificationAdapter so it can be registered with NotificationService.
 *
 * Features:
 * - URL validation: validates the webhook URL before sending
 * - JSON payload formatting: converts NotificationPayload to a structured JSON body
 * - Pluggable transport: swap the transport function for real HTTP integration
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface WebhookConfig {
  /** The URL to POST webhook payloads to. */
  url: string;
  /** Optional secret for signing webhook payloads. */
  secret?: string;
}

/**
 * The JSON body sent to the webhook endpoint.
 */
export interface WebhookPayload {
  event: string;
  notification: {
    id: string;
    type: string;
    channel: string;
    recipient: string;
    subject: string;
    body: string;
    priority: string;
    metadata: Record<string, string>;
    createdAt: string;
  };
  timestamp: string;
}

/**
 * Transport function signature — swap this to integrate with a real HTTP client.
 * The default transport is a no-op (for development / testing).
 */
export type WebhookTransport = (url: string, payload: WebhookPayload) => Promise<void>;

/**
 * Default transport: no-op (for development / testing).
 */
const noopTransport: WebhookTransport = async () => {};

// ---------- Validation ----------

const URL_REGEX = /^https?:\/\/.+/;

/**
 * Validate that a string looks like a valid webhook URL.
 */
export function isValidWebhookUrl(url: string): boolean {
  return URL_REGEX.test(url);
}

// ---------- Adapter ----------

export class WebhookAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private config: WebhookConfig;
  private transport: WebhookTransport;
  private deliveredPayloads: Array<{ webhookPayload: WebhookPayload; payload: NotificationPayload; timestamp: Date }> = [];

  constructor(config: WebhookConfig, transport?: WebhookTransport) {
    this.config = config;
    this.transport = transport ?? noopTransport;
  }

  /**
   * Format a NotificationPayload into the JSON body sent to the webhook endpoint.
   */
  formatPayload(payload: NotificationPayload): WebhookPayload {
    return {
      event: `notification.${payload.type}`,
      notification: {
        id: payload.id,
        type: payload.type,
        channel: payload.channel,
        recipient: payload.recipient,
        subject: payload.subject,
        body: payload.body,
        priority: payload.priority,
        metadata: payload.metadata,
        createdAt: payload.createdAt.toISOString(),
      },
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Validate the configured webhook URL.
   * Returns the URL or throws if invalid.
   */
  validateUrl(): string {
    const url = this.config.url.trim();
    if (!isValidWebhookUrl(url)) {
      throw new Error(`Invalid webhook URL: ${this.config.url}`);
    }
    return url;
  }

  /**
   * Send a notification via webhook POST.
   *
   * Flow: validate URL → format payload → POST via transport → return result.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // 1. Validate URL
      const url = this.validateUrl();

      this.logger.info(
        `Sending webhook to ${url}: "${payload.subject}"`,
      );

      // 2. Format payload
      const webhookPayload = this.formatPayload(payload);

      // 3. POST via transport
      await this.transport(url, webhookPayload);

      // 4. Record for testing / auditing
      this.deliveredPayloads.push({ webhookPayload, payload, timestamp: new Date() });

      this.logger.info(
        `Webhook delivered to ${url} (notification: ${payload.id})`,
      );

      return {
        success: true,
        channel: 'webhook',
        deliveredAt: new Date(),
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown webhook error';
      this.logger.error(`Webhook delivery failed for ${this.config.url}: ${message}`);

      return {
        success: false,
        channel: 'webhook',
        error: message,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get all payloads delivered through this adapter (for testing/debugging).
   */
  getDeliveredPayloads(): Array<{ webhookPayload: WebhookPayload; payload: NotificationPayload; timestamp: Date }> {
    return [...this.deliveredPayloads];
  }

  /**
   * Clear delivered payload history (for testing).
   */
  clearDeliveredPayloads(): void {
    this.deliveredPayloads = [];
  }
}

